def process_graph(graph_data):
    # Create a copy of the graph
    graph_copy = graph_data.copy()

    # Find the AGG_BLOCK node with name ju1.a4.m3
    target_agg_block = None
    for node in graph_copy.nodes(data=True):
        if node[1].get('name') == 'ju1.a4.m3' and 'EK_AGG_BLOCK' in node[1].get('type', []):
            target_agg_block = node[0]
            break

    if not target_agg_block:
        return_object = {
            'type': 'text',
            'data': 'AGG_BLOCK node ju1.a4.m3 not found',
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }
        return return_object

    # Find all direct children of the AGG_BLOCK via RK_CONTAINS edges
    children = []
    for edge in graph_copy.out_edges(target_agg_block, data=True):
        if edge[2].get('type') == 'RK_CONTAINS':
            child_id = edge[1]
            child_data = graph_copy.nodes[child_id]
            if 'EK_PACKET_SWITCH' in child_data.get('type', []):
                children.append(child_id)

    # Calculate capacity for each child
    child_capacities = []
    for child_id in children:
        child_name = graph_copy.nodes[child_id].get('name', child_id)

        # Get total physical capacity for this child
        total_capacity = 0
        stack = [child_id]
        visited = set()

        while stack:
            current = stack.pop()
            if current in visited:
                continue
            visited.add(current)

            current_data = graph_copy.nodes[current]
            # If this is a PORT node, add its capacity
            if 'EK_PORT' in current_data.get('type', []):
                capacity = current_data.get('physical_capacity_bps', 0)
                total_capacity += capacity

            # Add children via RK_CONTAINS edges
            for edge in graph_copy.out_edges(current, data=True):
                if edge[2].get('type') == 'RK_CONTAINS':
                    stack.append(edge[1])

        child_capacities.append((child_name, total_capacity))

    # Sort by capacity (descending)
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    # Prepare return object
    return_object = {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

    return return_object

