def process_graph(graph_data):
    # Create a copy of the graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # Find and remove the port node with name 'ju1.s1.s2c2.p10'
    nodes_to_remove = []
    for node, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s1.s2c2.p10' and 'EK_PORT' in attrs.get('type', []):
            nodes_to_remove.append(node)

    # Remove the identified nodes from the graph copy
    for node in nodes_to_remove:
        graph_copy.remove_node(node)

    # Find the target node 'ju1.s1.s2c2'
    target_node = None
    for node, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s1.s2c2':
            target_node = node
            break

    # Count EK_PORT nodes contained within the target node
    port_count = 0
    if target_node:
        # Check all successors connected by RK_CONTAINS edges
        for successor in graph_copy.successors(target_node):
            edge_data = graph_copy.get_edge_data(target_node, successor)
            if edge_data and edge_data.get('type') == 'RK_CONTAINS':
                successor_attrs = graph_copy.nodes[successor]
                if 'EK_PORT' in successor_attrs.get('type', []):
                    port_count += 1

    # Prepare the return object
    return_object = {
        'type': 'text',
        'data': str(port_count),
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

    return return_object
